# Apply multiple methods and combine results
ensemble_result = (
    AnomalyPipe.from_dataframe(df)
    | batch_detect_anomalies(
        columns=['metric'],
        methods=[
            {'name': 'statistical_outliers', 'params': {'method': 'zscore', 'threshold': 2.5}},
            {'name': 'contextual_anomalies', 'params': {'time_column': 'date', 'method': 'residual'}}
        ],
        ensemble_method='majority'
    )
)

# Stress test portfolio under crisis scenarios
stress_results = (
    RiskPipe.from_dataframe(df)
    | stress_test(
        columns=['portfolio_returns'],
        scenarios={
            'market_crash': {'returns': -0.20, 'volatility': 0.40},
            'recession': {'returns': -0.10, 'volatility': 0.25}
        }
    )
)

stress_metrics = stress_results.stress_tests

# Create segments using business logic
rule_segments = (
    SegmentationPipe.from_dataframe(df)
    | run_rule_based(
        rules={
            'vip_customers': {
                'total_spent': ('>', 10000),
                'frequency': ('>', 50)
            },
            'at_risk': {
                'recency': ('>', 90),
                'frequency': ('>', 10)
            }
        }
    )
    | generate_summary()
)
